                        <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">View</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }
    [SupplyParameterFromQuery] public int? Credits { get; set; }

    private List<Course> _courses = [];
    private List<Department> _departments = [];
    private List<int> _creditOptions = [];

    protected override void OnInitialized()
    {
        _departments = Catalog.GetDepartments();
        _creditOptions = Catalog.GetDistinctCredits();
        _courses = Catalog.GetCourses(Search, DepartmentId, Credits);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog
@inject EnrollmentService Enrollment
@inject NavigationManager Nav

<PageTitle>Enrollment Request — University Course Catalog</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@_model.FullName</strong>. Your enrollment request for <strong>@_selectedCourseTitle</strong> has been received.</p>
        <hr />
        <p class="mb-0">You will receive a confirmation at your university email. <a href="/courses">Browse more courses</a>.</p>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-8">
            <div class="card shadow-sm">
                <div class="card-body">
                    <p class="text-muted mb-4">Fill out the form below to request enrollment in a course. All fields marked with <span class="text-danger">*</span> are required.</p>

                    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="EnrollmentForm">
                        <DataAnnotationsValidator />
                        <ValidationSummary class="text-danger mb-3" />

                        <div class="mb-3">
                            <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
                            <InputText id="fullName" @bind-Value="_model.FullName" class="form-control" placeholder="e.g., Jane Doe" />
                            <ValidationMessage For="() => _model.FullName" class="text-danger" />
                        </div>

                        <div class="mb-3">
                            <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                            <InputText id="studentId" @bind-Value="_model.StudentId" class="form-control" placeholder="e.g., CS123456" />
                            <ValidationMessage For="() => _model.StudentId" class="text-danger" />
                        </div>

                        <div class="mb-3">
                            <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                            <InputSelect id="courseId" @bind-Value="_model.CourseId" class="form-select">
                                <option value="0">— Select a course —</option>
                                @foreach (var course in _courses)
                                {
                                    <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr.)</option>
                                }
                            </InputSelect>
                            <ValidationMessage For="() => _model.CourseId" class="text-danger" />
                        </div>

                        <div class="mb-3">
                            <label for="comments" class="form-label">Comments (optional)</label>
                            <InputTextArea id="comments" @bind-Value="_model.Comments" class="form-control" rows="3" placeholder="Any additional information…" />
                            <ValidationMessage For="() => _model.Comments" class="text-danger" />
                        </div>

                        <button type="submit" class="btn btn-primary">Submit Request</button>
                        <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
                    </EditForm>
                </div>
            </div>
        </div>

        <div class="col-lg-4">
            <div class="card bg-light">
                <div class="card-body">
                    <h5 class="card-title">How It Works</h5>
                    <ol class="mb-0">
                        <li class="mb-2">Enter your name and student ID.</li>
                        <li class="mb-2">Select the course you want to enroll in.</li>
                        <li class="mb-2">Submit the form — you'll receive a confirmation.</li>
                        <li>The registrar's office will process your request within 2 business days.</li>
                    </ol>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    [SupplyParameterFromForm] private EnrollmentRequest _model { get; set; } = new();

    private List<Course> _courses = [];
    private bool _submitted;
    private string _selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        _courses = Catalog.GetCourses();

        if (CourseId.HasValue && _model.CourseId == 0)
        {
            _model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = Catalog.GetCourse(_model.CourseId);
        _selectedCourseTitle = course is not null ? $"{course.Code} — {course.Title}" : "Unknown Course";
        Enrollment.Submit(_model);
        _submitted = true;
    }
}

